import React, { useEffect, useState } from "react";

function App() {
  let [message, setMessage] = useState("Ładowanie...");
  let [przepisy, setPrzepisy] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5000/")
      .then((response) => response.json())
      .then((data) => {
        console.log("Dane z / :", data);
        setMessage(data.message || "Brak komunikatu");
      })
      .catch((error) => {
        console.log("Błąd / :", error);
        setMessage("Błąd połączenia z backendem");
      });

    fetch("http://localhost:5000/przepisy")
      .then((response) => response.json())
      .then((data) => {
        console.log("Dane z /przepisy:", data);

        if (Array.isArray(data)) {
          setPrzepisy(data);
        } else {
          setPrzepisy([]);
        }
      })
      .catch((error) => {
        console.log("Błąd /przepisy:", error);
        setPrzepisy([]);
      });
  }, []);

  return (
    <div style={{ padding: "20px" }}>
      <h1>Test React + Backend</h1>
      <p>Komunikat z backendu: {message}</p>

      <h2>Przepisy</h2>

      {przepisy.length === 0 ? (
        <p>Brak danych albo backend nie zwrócił tablicy</p>
      ) : (
        przepisy.map((przepis) => (
          <div
            key={przepis.id}
            style={{
              border: "1px solid #ccc",
              marginBottom: "10px",
              padding: "10px"
            }}
          >
            <h3>{przepis.tytul}</h3>
            <p>{przepis.opis}</p>
            <p>Czas: {przepis.czas_przygotowania_min} min</p>
            <p>Trudność: {przepis.poziom_trudnosci}</p>
          </div>
        ))
      )}
    </div>
  );
}

export default App;
